mapper.select:
SELECT ,
FROM task t LEFT JOIN category c ON t.category_id = c.id AND c.deleted = 0 LEFT JOIN `user` u ON t.user_id = u.id AND u.deleted = 0 LEFT JOIN task_accept ta ON ta.task_id = t.id AND ta.deleted = 0 AND ta.status IN (0, 1) LEFT JOIN `user` ua ON ta.user_id = ua.id AND ua.deleted = 0
t.deleted = 0
AND t.title LIKE CONCAT('%', #{req.keyword}, '%')
AND t.category_id = #{req.categoryId}
AND t.status = #{req.status}
AND t.user_id = #{req.userId}
ORDER BY t.create_time DESC
